create or replace function public.post_payroll_run(p_organization_id uuid,p_payroll_run_id uuid,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare r public.payroll_runs%rowtype; v_journal uuid; v_no text; salary_expense uuid; employer_pension_expense uuid; payroll_payable uuid; pension_payable uuid; tax_payable uuid; deductions_payable uuid; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant']::public.app_role[]) then raise exception 'Insufficient payroll posting permission'; end if; select * into r from public.payroll_runs where id=p_payroll_run_id and organization_id=p_organization_id for update; if not found or r.status<>'approved' then raise exception 'Approved payroll run not found'; end if; insert into public.accounts(organization_id,code,name,account_type,account_subtype,normal_side,is_system,is_active,allow_manual_posting) values(p_organization_id,'2300','Payroll Payable','liability','payroll_payable','credit',true,true,false),(p_organization_id,'2310','Pension Payable','liability','pension_payable','credit',true,true,false),(p_organization_id,'2320','Payroll Tax Payable','liability','payroll_tax','credit',true,true,false),(p_organization_id,'2330','Other Payroll Deductions Payable','liability','payroll_deductions','credit',true,true,false),(p_organization_id,'6200','Salaries and Wages','expense','payroll_expense','debit',true,true,false),(p_organization_id,'6210','Employer Pension Expense','expense','pension_expense','debit',true,true,false) on conflict(organization_id,code) do nothing; select id into salary_expense from public.accounts where organization_id=p_organization_id and code='6200'; select id into employer_pension_expense from public.accounts where organization_id=p_organization_id and code='6210'; select id into payroll_payable from public.accounts where organization_id=p_organization_id and code='2300'; select id into pension_payable from public.accounts where organization_id=p_organization_id and code='2310'; select id into tax_payable from public.accounts where organization_id=p_organization_id and code='2320'; select id into deductions_payable from public.accounts where organization_id=p_organization_id and code='2330'; v_no:=public.next_document_number(p_organization_id,'JE'); insert into public.journal_entries(organization_id,branch_id,entry_number,entry_date,memo,status,source_type,created_by) values(p_organization_id,r.branch_id,v_no,r.pay_date,'Payroll '||r.payroll_number,'draft','payroll_run',p_actor_id) returning id into v_journal; insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,salary_expense,'Gross payroll',r.gross_pay,0),(p_organization_id,v_journal,payroll_payable,'Net payroll payable',0,r.net_pay); if r.employer_pension>0 then insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,employer_pension_expense,'Employer pension expense',r.employer_pension,0); end if; if r.employee_pension+r.employer_pension>0 then insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,pension_payable,'Pension payable',0,r.employee_pension+r.employer_pension); end if; if r.income_tax>0 then insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,tax_payable,'Payroll tax payable',0,r.income_tax); end if; if r.other_deductions>0 then insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,deductions_payable,'Other deductions payable',0,r.other_deductions); end if; update public.journal_entries set status='posted',source_id=r.id,posted_by=p_actor_id,posted_at=now() where id=v_journal; update public.payroll_runs set status='posted',journal_entry_id=v_journal,posted_by=p_actor_id,posted_at=now(),updated_at=now() where id=r.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'payroll.run.posted','payroll_run',r.id,jsonb_build_object('number',r.payroll_number,'journal',v_journal,'net_pay',r.net_pay)); return jsonb_build_object('id',r.id,'number',r.payroll_number,'amount',r.net_pay); end $$;

revoke all on function public.post_payroll_run(uuid,uuid,uuid) from public;
grant execute on function public.post_payroll_run(uuid,uuid,uuid) to authenticated;